// Description: Collects memory utilization metrics for a KubeVirt VMI via Thanos Querier.
// Description: Uses executeQuery() helper with Math.max clamp for used memory calculation.
import groovy.json.JsonSlurper
import javax.net.ssl.*
import java.security.cert.X509Certificate

def host = hostProps.get("kubevirt.thanos.host")
def token = hostProps.get("kubevirt.thanos.pass")
def port = hostProps.get("kubevirt.thanos.port") ?: "443"
def useSsl = (hostProps.get("kubevirt.thanos.ssl") ?: "true").toLowerCase() == "true"

def vmiName = instanceProps.get("auto.vmi.name")

if (!host || !token || !vmiName) {
    println("memory_usage_percent:0")
    println("memory_available_bytes:0")
    println("memory_used_bytes:0")
    println("memory_domain_bytes:0")
    println("memory_resident_bytes:0")
    println("memory_cached_bytes:0")
    println("memory_unused_bytes:0")
    println("memory_swap_in_bytes:0")
    println("memory_swap_out_bytes:0")
    println("memory_pgmajfault:0")
    return 0
}

def trustAllCerts = [
    checkClientTrusted: { chain, authType -> },
    checkServerTrusted: { chain, authType -> },
    getAcceptedIssuers: { null }
] as X509TrustManager

def sc = SSLContext.getInstance("TLS")
sc.init(null, [trustAllCerts] as TrustManager[], null)
HttpsURLConnection.setDefaultSSLSocketFactory(sc.getSocketFactory())
HttpsURLConnection.setDefaultHostnameVerifier({ hostname, session -> true } as HostnameVerifier)

def proto = useSsl ? "https" : "http"
def baseUrl = "${proto}://${host}:${port}"

def executeQuery(String promql, String baseUrl, String token) {
    try {
        def encoded = java.net.URLEncoder.encode(promql, "UTF-8")
        def url = new URL("${baseUrl}/api/v1/query?query=${encoded}")
        def conn = url.openConnection()
        conn.setRequestProperty("Authorization", "Bearer ${token}")
        conn.setConnectTimeout(30000)
        conn.setReadTimeout(30000)

        if (conn.responseCode == 200) {
            def response = conn.inputStream.text
            def json = new JsonSlurper().parseText(response)
            if (json.status == "success" && json.data?.result?.size() > 0) {
                def val = json.data.result[0].value[1]
                return val?.toString()?.isNumber() ? val : null
            }
        } else {
            System.err.println("Query failed: HTTP ${conn.responseCode} for: ${promql}")
        }
    } catch (Exception e) {
        System.err.println("Query error for ${promql}: ${e.message}")
    }
    return null
}

def queries = [
    "memory_available_bytes": 'kubevirt_vmi_memory_available_bytes{name="' + vmiName + '"}',
    "memory_domain_bytes": 'kubevirt_vmi_memory_domain_bytes{name="' + vmiName + '"}',
    "memory_resident_bytes": 'kubevirt_vmi_memory_resident_set_size_bytes{name="' + vmiName + '"}',
    "memory_cached_bytes": 'kubevirt_vmi_memory_cached_bytes{name="' + vmiName + '"}',
    "memory_unused_bytes": 'kubevirt_vmi_memory_unused_bytes{name="' + vmiName + '"}',
    "memory_swap_in_bytes": 'kubevirt_vmi_memory_swap_in_traffic_bytes{name="' + vmiName + '"}',
    "memory_swap_out_bytes": 'kubevirt_vmi_memory_swap_out_traffic_bytes{name="' + vmiName + '"}',
    "memory_pgmajfault": 'rate(kubevirt_vmi_memory_pgmajfault_total{name="' + vmiName + '"}[5m])'
]

def raw = [:]
queries.each { k, q ->
    def val = executeQuery(q, baseUrl, token)
    raw[k] = val != null ? (val as Double) : 0
}

def memDomain = raw["memory_domain_bytes"]
def memAvail = raw["memory_available_bytes"]
def memUsed = Math.max(0, memDomain - memAvail)
def memPct = memDomain > 0 ? (memUsed / memDomain) * 100 : 0

println("memory_usage_percent:" + memPct)
println("memory_available_bytes:" + memAvail)
println("memory_used_bytes:" + memUsed)
println("memory_domain_bytes:" + memDomain)
println("memory_resident_bytes:" + raw["memory_resident_bytes"])
println("memory_cached_bytes:" + raw["memory_cached_bytes"])
println("memory_unused_bytes:" + raw["memory_unused_bytes"])
println("memory_swap_in_bytes:" + raw["memory_swap_in_bytes"])
println("memory_swap_out_bytes:" + raw["memory_swap_out_bytes"])
println("memory_pgmajfault:" + raw["memory_pgmajfault"])

return 0
